import { create } from 'zustand';
import type { GeoJSONFeature } from '../types/spatial';

interface FeatureState {
  selectedFeature: GeoJSONFeature | null;
  hoveredFeature: GeoJSONFeature | null;
}

interface FeatureActions {
  setSelectedFeature: (feature: GeoJSONFeature | null) => void;
  setHoveredFeature: (feature: GeoJSONFeature | null) => void;
  clearSelection: () => void;
}

/**
 * 선택된 지리 객체와 해당 속성을 관리하는 Zustand 스토어
 */
export const useFeatureStore = create<FeatureState & FeatureActions>((set) => ({
  selectedFeature: null,
  hoveredFeature: null,

  setSelectedFeature: (feature) => set({ selectedFeature: feature }),
  setHoveredFeature: (feature) => set({ hoveredFeature: feature }),
  clearSelection: () => set({ selectedFeature: null, hoveredFeature: null }),
}));

import { create } from 'zustand';
import type { LayerInfo } from '../types/spatial';

interface MapState {
  zoom: number;
  center: [number, number];
  layers: LayerInfo[];
}

interface MapActions {
  setZoom: (zoom: number) => void;
  setCenter: (center: [number, number]) => void;
  addLayer: (layer: LayerInfo) => void;
  removeLayer: (id: string) => void;
  toggleLayerVisibility: (id: string) => void;
}

/**
 * 지도 관련 전역 상태를 관리하는 Zustand 스토어
 */
export const useMapStore = create<MapState & MapActions>((set) => ({
  zoom: 13,
  center: [37.5665, 126.9780], // 서울 중심좌표
  layers: [],

  setZoom: (zoom) => set({ zoom }),
  setCenter: (center) => set({ center }),

  addLayer: (layer) => set((state) => {
    const id = layer.id || `layer-${Date.now()}`;
    // 이미 동일한 ID가 있다면 추가하지 않거나 덮어쓰지 않음 (필요시 로직 조정 가능)
    if (state.layers.some((l) => l.id === id)) {
      return state;
    }
    return {
      layers: [...state.layers, { ...layer, id }]
    };
  }),

  removeLayer: (id) => set((state) => ({
    layers: state.layers.filter((l) => l.id !== id)
  })),

  toggleLayerVisibility: (id) => set((state) => ({
    layers: state.layers.map((l) => 
      l.id === id ? { ...l, visible: !l.visible } : l
    )
  })),
}));

import type { Feature, Geometry } from 'geojson';

/**
 * 서버에서 반환하는 공간 분석 결과 데이터 구조
 */
export interface SpatialAnalysisResult {
  id: number;
  filename: string;
  original_name: string;
  upload_time: string;
  analysis_results: Array<{
    feature_index: number;
    area_sqm: number;
    area_pyung: number;
    properties: Record<string, any>;
    geometry_type: string;
  }>;
}

/**
 * 지도 레이어의 메타데이터 및 상태 정보
 */
export interface LayerInfo {
  id: string;
  name: string;
  visible: boolean;
  data: any; // GeoJSON 데이터
  analysis?: SpatialAnalysisResult;
}

/**
 * GeoJSON Feature 타입 확장
 */
export type GeoJSONFeature = Feature<Geometry, Record<string, any>>;
